-- ================================================== \n-- Initial Database Schema for Eman Bakery Tray Tracking\n-- ==================================================\n\n-- Create branches table\nCREATE TABLE IF NOT EXISTS branches (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  name VARCHAR(255) NOT NULL,\n  code VARCHAR(10) NOT NULL UNIQUE,\n  status VARCHAR(20) NOT NULL DEFAULT 'active' CHECK (status IN ('active', 'inactive')),\n  created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Create users table\nCREATE TABLE IF NOT EXISTS users (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  email VARCHAR(255) NOT NULL UNIQUE,\n  full_name VARCHAR(255) NOT NULL,\n  password_hash VARCHAR(255) NOT NULL,\n  role VARCHAR(50) NOT NULL CHECK (role IN ('admin', 'branch_staff')),\n  branch_id UUID REFERENCES branches(id) ON DELETE SET NULL,\n  status VARCHAR(20) NOT NULL DEFAULT 'active' CHECK (status IN ('active', 'inactive', 'suspended')),\n  created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  last_login TIMESTAMP\n);\n\n-- Create salesman_profiles table\nCREATE TABLE IF NOT EXISTS salesman_profiles (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  name VARCHAR(255) NOT NULL,\n  phone VARCHAR(20),\n  branch_id UUID NOT NULL REFERENCES branches(id) ON DELETE RESTRICT,\n  status VARCHAR(20) NOT NULL DEFAULT 'active' CHECK (status IN ('active', 'inactive')),\n  total_outstanding_trays INTEGER NOT NULL DEFAULT 0 CHECK (total_outstanding_trays >= 0),\n  created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Create opening_stock table (immutable)\nCREATE TABLE IF NOT EXISTS opening_stock (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  branch_id UUID NOT NULL UNIQUE REFERENCES branches(id) ON DELETE RESTRICT,\n  initial_quantity INTEGER NOT NULL CHECK (initial_quantity >= 0),\n  recorded_by_user_id UUID NOT NULL REFERENCES users(id) ON DELETE RESTRICT,\n  recorded_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Create tray_transactions table (append-only, immutable)\nCREATE TABLE IF NOT EXISTS tray_transactions (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  type VARCHAR(50) NOT NULL CHECK (type IN ('issuance', 'return')),\n  salesman_id UUID NOT NULL REFERENCES salesman_profiles(id) ON DELETE RESTRICT,\n  branch_id UUID NOT NULL REFERENCES branches(id) ON DELETE RESTRICT,\n  quantity INTEGER NOT NULL CHECK (quantity > 0),\n  recorded_by_user_id UUID NOT NULL REFERENCES users(id) ON DELETE RESTRICT,\n  status VARCHAR(20) NOT NULL DEFAULT 'completed' CHECK (status IN ('completed', 'blocked', 'reversed', 'pending')),\n  block_reason TEXT,\n  transaction_timestamp TIMESTAMP NOT NULL,\n  created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Create audit_logs table (immutable)\nCREATE TABLE IF NOT EXISTS audit_logs (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  action VARCHAR(255) NOT NULL,\n  user_id UUID REFERENCES users(id) ON DELETE SET NULL,\n  resource_type VARCHAR(100) NOT NULL,\n  resource_id UUID NOT NULL,\n  changes JSONB NOT NULL,\n  ip_address INET,\n  created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP\n);\n\n-- ================================================== \n-- Views for Real-Time Stock Calculation\n-- ==================================================\n\n-- Stock balance view (real-time calculation)\nCREATE OR REPLACE VIEW stock_balance AS\nSELECT \n  b.id as branch_id,\n  b.name as branch_name,\n  COALESCE(os.initial_quantity, 0) as initial_stock,\n  COALESCE(SUM(CASE WHEN tt.type = 'issuance' THEN tt.quantity ELSE 0 END), 0) as total_issued,\n  COALESCE(SUM(CASE WHEN tt.type = 'return' THEN tt.quantity ELSE 0 END), 0) as total_returned,\n  COALESCE(os.initial_quantity, 0) - COALESCE(SUM(CASE WHEN tt.type = 'issuance' THEN tt.quantity ELSE 0 END), 0) + COALESCE(SUM(CASE WHEN tt.type = 'return' THEN tt.quantity ELSE 0 END), 0) as current_stock,\n  CURRENT_TIMESTAMP as last_updated\nFROM branches b\nLEFT JOIN opening_stock os ON b.id = os.branch_id\nLEFT JOIN tray_transactions tt ON b.id = tt.branch_id AND tt.status = 'completed'\nGROUP BY b.id, b.name, os.initial_quantity;\n\n-- ================================================== \n-- Indexes for Performance Optimization\n-- ==================================================\n\nCREATE INDEX idx_users_email ON users(email);\nCREATE INDEX idx_users_branch_id ON users(branch_id);\nCREATE INDEX idx_salesman_branch_id ON salesman_profiles(branch_id);\nCREATE INDEX idx_opening_stock_branch_id ON opening_stock(branch_id);\nCREATE INDEX idx_transactions_salesman_id ON tray_transactions(salesman_id);\nCREATE INDEX idx_transactions_branch_id ON tray_transactions(branch_id);\nCREATE INDEX idx_transactions_type ON tray_transactions(type);\nCREATE INDEX idx_transactions_status ON tray_transactions(status);\nCREATE INDEX idx_transactions_timestamp ON tray_transactions(transaction_timestamp);\nCREATE INDEX idx_audit_logs_user_id ON audit_logs(user_id);\nCREATE INDEX idx_audit_logs_resource ON audit_logs(resource_type, resource_id);\nCREATE INDEX idx_audit_logs_created_at ON audit_logs(created_at);\n\n-- ================================================== \n-- Constraints\n-- ==================================================\n\n-- Ensure each branch has at most one opening stock record\nALTER TABLE opening_stock ADD CONSTRAINT unique_branch_opening_stock UNIQUE (branch_id);\n\n-- Ensure salesman belongs to branch where transactions occur\nALTER TABLE tray_transactions\nADD CONSTRAINT salesman_branch_consistency\nCHECK (branch_id = (SELECT branch_id FROM salesman_profiles WHERE id = salesman_id));\n\n-- ================================================== \n-- Row-Level Security (Optional)\n-- ==================================================\n\n-- Enable RLS on sensitive tables\nALTER TABLE users ENABLE ROW LEVEL SECURITY;\nALTER TABLE tray_transactions ENABLE ROW LEVEL SECURITY;\nALTER TABLE audit_logs ENABLE ROW LEVEL SECURITY;\n\n-- ================================================== \n-- Triggers for Audit Logging\n-- ==================================================\n\nCREATE OR REPLACE FUNCTION audit_transaction_changes()\nRETURNS TRIGGER AS $$\nBEGIN\n  INSERT INTO audit_logs (action, user_id, resource_type, resource_id, changes)\n  VALUES (\n    TG_OP,\n    CURRENT_SETTING('app.current_user_id')::UUID,\n    'tray_transactions',\n    COALESCE(NEW.id, OLD.id),\n    jsonb_build_object(\n      'old', row_to_json(OLD),\n      'new', row_to_json(NEW)\n    )\n  );\n  RETURN COALESCE(NEW, OLD);\nEND;\n$$ LANGUAGE plpgsql;\n\nCREATE TRIGGER tray_transactions_audit_trigger\nAFTER INSERT OR UPDATE ON tray_transactions\nFOR EACH ROW\nEXECUTE FUNCTION audit_transaction_changes();\n\n-- ================================================== \n-- Permissions (for Supabase Auth Integration)\n-- ==================================================\n\n-- Grant appropriate permissions to authenticated users\nGRANT SELECT ON branches TO authenticated;\nGRANT SELECT ON users TO authenticated;\nGRANT SELECT ON salesman_profiles TO authenticated;\nGRANT SELECT ON tray_transactions TO authenticated;\nGRANT SELECT ON stock_balance TO authenticated;\n\n-- Admin-only operations\nGRANT INSERT, UPDATE, DELETE ON users TO authenticated;\nGRANT INSERT, UPDATE, DELETE ON branches TO authenticated;\nGRANT INSERT ON opening_stock TO authenticated;\nGRANT INSERT ON tray_transactions TO authenticated;\n", "path": "supabase/migrations/001_initial_schema.sql", "message": "Add database schema with complete tables, views, and indexes", "owner": "emanbakery", "repo": "emanbakery-tray-tracking"}]